// Gather each check's output (each upstream node emits exactly one item).
function check(name) {
  try {
    const j = $(name).item.json;
    if (j && (j.error || j.errorMessage)) {
      return { ok: false, detail: String(j.error || j.errorMessage).slice(0, 300), json: j };
    }
    return { ok: true, detail: 'ok', json: j };
  } catch (e) {
    return { ok: false, detail: 'no response: ' + e.message };
  }
}

const checks = {
  qdrant: check('Check Qdrant'),
  ollama: check('Check Ollama'),
  postgres: check('Check Postgres'),
};

// Ollama /api/tags should return a models array
if (checks.ollama.ok) {
  const m = checks.ollama.json && checks.ollama.json.models;
  if (!Array.isArray(m)) checks.ollama = { ok: false, detail: 'unexpected /api/tags response' };
}

// Postgres SELECT 1 should return ok=1
if (checks.postgres.ok) {
  const v = checks.postgres.json && (checks.postgres.json.ok ?? checks.postgres.json['?column?']);
  if (Number(v) !== 1) checks.postgres = { ok: false, detail: 'SELECT 1 did not return 1' };
}

const failures = Object.entries(checks)
  .filter(([, v]) => !v.ok)
  .map(([k, v]) => `${k}: ${v.detail}`);

// Failed ingestion rows
let failedDocs = 0;
try {
  const fd = $('Check Failed Docs').item.json;
  failedDocs = Number(fd.failed_count ?? fd.count ?? 0) || 0;
} catch (e) { /* table/credential issue already surfaced via postgres check */ }
if (failedDocs > 0) failures.push(`knowledge_documents: ${failedDocs} row(s) with status='failed'`);

const healthy = failures.length === 0;
const ts = new Date().toISOString();
const summary = healthy
  ? `All systems OK at ${ts}`
  : `AI-Ops health check FAILED at ${ts}\n\n` +
    failures.map(f => `\u2022 ${f}`).join('\n') +
    `\n\nChecked: Qdrant /healthz, Ollama /api/tags, Postgres SELECT 1, knowledge_documents.status='failed'.`;

return [{ json: { healthy, failures, failed_docs: failedDocs, summary, checked_at: ts } }];
